/* wms-master-master-sql-oracle.xml - insertInterfaceCenter */
INSERT INTO TWORK_INTF_CT_RCV (
	   CTKEY			/* 센터코드 */
	 , CTNM				/* 센터명 */
	 , CTTYPECD			/* 센터유형 */
	 , REGNO			/* 사업자등록번호 */
	 , CNTRYCD			/* 국가코드 */
	 , ZIPCD			/* 우편번호 */
	 , ADDR1			/* 주소1 */
	 , ADDR2			/* 주소2 */
	 , TELNO			/* 전화번호 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{ctname}
	 , #{cttype}
	 , #{regno}
	 , #{countrycode}
	 , #{zipcode}
	 , #{address1}
	 , #{address2}
	 , #{tel}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

